const channel = api.getTargetChannel();
const now = new Date();
const fromIso = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();
const toIso = now.toISOString();
const summary = api.summarizeChannel({ channelId: channel.id, fromIso, toIso });
return { channelId: channel.id, fromIso, toIso, summary: summary.summary, topics: summary.topics, actionItems: summary.actionItems };

